def strlen(string: str) -> int:
    """ Return length of given string
    >>> strlen('')
    0
    >>> strlen('abc')
    3
    """
    def recursive_length(s: str, count: int = 0) -> int:
        if s == '':
            return count
        else:
            return recursive_length(s[1:], count + 1)

    return recursive_length(string)
